#include<bits/stdc++.h>
using namespace std;
long long n;
bool flag=false;
int main(){
	cin>>n;
	for(long long i=2;i<=sqrt(n);i++)
    {
		if(n%i==0)
        {
			int s=0;
			while(n%i==0){
				n/=i;
				s++;
			}
			if(flag) cout<<"* ";
			if(s!=1) cout<<i<<'^'<<s<<' ';
			else cout<<i<<' ';
            flag=true;
		}
	}
	if(n!=1)
    {
		if(flag) cout<<"* "<<n;
		else cout<<n;
	}
	return 0;
}
